  1	import * as React from 'react';
  2	import {
  3	  useCustomPrometheusPoll,
  4	  usePrometheusBasePath,
  5	} from '@odf/shared/hooks/custom-prometheus-poll';
  6	import {
  7	  Humanize,
  8	  K8sKind,
  9	  K8sResourceCommon,
 10	  useK8sWatchResource,
 11	} from '@openshift-console/dynamic-plugin-sdk';
 12	import { Link } from 'react-router-dom-v5-compat';
 13	import {
 14	  Dropdown,
 15	  DropdownItem,
 16	  DropdownList,
 17	  MenuToggle,
 18	  MenuToggleElement,
 19	  PopoverPosition,
 20	  Popover,
 21	  Button,
 22	} from '@patternfly/react-core';
 23	import { CaretDownIcon } from '@patternfly/react-icons';
 24	import { getName, getNamespace } from '../../selectors';
 25	import { useCustomTranslation } from '../../useCustomTranslationHook';
 26	import {
 27	  DataPoint,
 28	  getInstantVectorStats,
 29	  referenceForModel,
 30	  resourcePathFromModel,
 31	} from '../../utils';
 32	
 33	export type ConsumerPopoverProps = PopoverProps & {
 34	  position?: PopoverPosition;
 35	  title: string;
 36	  current: string;
 37	  namespace?: string;
 38	  humanize: any;
 39	  description?: any;
 40	  consumers?: any;
 41	  basePath?: string;
 42	};
 43	
 44	const ConsumerPopover: React.FC<ConsumerPopoverProps> = React.memo(
 45	  ({
 46	    current,
 47	    title,
 48	    humanize,
 49	    consumers,
 50	    namespace,
 51	    position = PopoverPosition.top,
 52	    description,
 53	    children,
 54	    basePath,
 55	  }) => {
 56	    const { t } = useCustomTranslation();
 57	    const [isOpen, setOpen] = React.useState(false);
 58	    const onShow = React.useCallback(() => setOpen(true), []);
 59	    const onHide = React.useCallback(() => setOpen(false), []);
 60	    if (!current) {
 61	      return null;
 62	    }
 63	    return (
 64	      <Popover
 65	        position={position}
 66	        headerContent={t('{{title}} breakdown', { title })}
 67	        bodyContent={
 68	          <PopoverBody
 69	            humanize={humanize}
 70	            consumers={consumers}
 71	            namespace={namespace}
 72	            isOpen={isOpen}
 73	            description={description}
 74	            basePath={basePath}
 75	          >
 76	            {children}
 77	          </PopoverBody>
 78	        }
 79	        enableFlip
 80	        onShow={onShow}
 81	        onHide={onHide}
 82	        maxWidth="21rem"
 83	      >
 84	        <Button variant="link" isInline>
 85	          {current}
 86	        </Button>
 87	      </Popover>
 88	    );
 89	  }
 90	);
 91	
 92	type PopoverProps = {
 93	  humanize: Humanize;
 94	  consumers: {
 95	    model: K8sKind;
 96	    query: string;
 97	    metric: string;
 98	    fieldSelector?: string;
 99	  }[];
100	  namespace?: string;
101	  description?: string;
102	};
103	
104	type PopoverBodyProps = PopoverProps & {
105	  topConsumers?: DataPoint[][];
106	  error?: boolean;
107	  isOpen: boolean;
108	  humanize: Humanize;
109	  basePath?: string;
110	};
111	
112	const getResourceToWatch = (
113	  model: K8sKind,
114	  namespace: string,
115	  fieldSelector: string
116	) => ({
117	  isList: true,
118	  kind: model.crd ? referenceForModel(model) : model.kind,
119	  fieldSelector,
120	  namespace,
121	});
122	
123	const ListItem: React.FC<ListItemProps> = ({ children, value }) => (
124	  <li className="co-utilization-card-popover__consumer-item">
125	    {children}
126	    <div className="co-utilization-card-popover__consumer-value">{value}</div>
127	  </li>
128	);
129	
130	type ListItemProps = {
131	  value: React.ReactText;
132	};
133	
134	export const PopoverBody: React.FC<PopoverBodyProps> = React.memo(
135	  ({
136	    humanize,
137	    consumers,
138	    namespace,
139	    isOpen,
140	    description,
141	    children,
142	    basePath,
143	  }) => {
144	    const { t } = useCustomTranslation();
145	    const defaultBasePath = usePrometheusBasePath();
146	    const [currentConsumer, setCurrentConsumer] = React.useState(consumers[0]);
147	    const [dropdownOpen, setDropdownOpen] = React.useState(false);
148	    const { query, model, metric, fieldSelector } = currentConsumer;
149	    const k8sResource = React.useMemo(
150	      () =>
151	        isOpen ? getResourceToWatch(model, namespace, fieldSelector) : null,
152	      [fieldSelector, isOpen, model, namespace]
153	    );
154	    const [consumerData, consumerLoaded, consumersLoadError] =
155	      useK8sWatchResource<K8sResourceCommon[]>(k8sResource);
156	
157	    const [metrics, metricsError, metricsLoading] = useCustomPrometheusPoll({
158	      endpoint: isOpen ? ('api/v1/query' as any) : null,
159	      query: isOpen ? query : null,
160	      namespace,
161	      basePath: basePath || defaultBasePath,
162	    });
163	
164	    const top5Data = [];
165	
166	    const bodyData = getInstantVectorStats(metrics, metric);
167	
168	    if (k8sResource && consumerLoaded && !consumersLoadError) {
169	      for (const d of bodyData) {
170	        const consumerExists = consumerData.some(
171	          (consumer) =>
172	            getName(consumer) === d.metric[metric] &&
173	            (model.namespaced
174	              ? getNamespace(consumer) === d.metric.namespace
175	              : true)
176	        );
177	        if (consumerExists) {
178	          top5Data.push({ ...d, y: humanize(d.y).string });
179	        }
180	        if (top5Data.length === 5) {
181	          break;
182	        }
183	      }
184	    }
185	
186	    const monitoringParams = React.useMemo(() => {
187	      const params = new URLSearchParams();
188	      params.set('query0', currentConsumer.query);
189	      return params;
190	    }, [currentConsumer.query]);
191	
192	    const dropdownItems = React.useMemo(
193	      () =>
194	        consumers.reduce((items, curr) => {
195	          const ref = referenceForModel(curr.model);
196	          const dropdownItem = (
197	            <DropdownItem key={ref} id={ref}>
198	              {t('By {{label}}', {
199	                label: curr.model.labelKey
200	                  ? t(curr.model.labelKey)
201	                  : curr.model.label,
202	              })}
203	            </DropdownItem>
204	          );
205	          return [...items, dropdownItem];
206	        }, []),
207	      [consumers, t]
208	    );
209	
210	    const onDropdownChange = React.useCallback(
211	      (event: React.SyntheticEvent<HTMLDivElement>) => {
212	        event.preventDefault();
213	        event.stopPropagation();
214	        setCurrentConsumer(
215	          consumers.find(
216	            (c) => referenceForModel(c.model) === event?.currentTarget?.id
217	          )
218	        );
219	        setDropdownOpen((o) => !o);
220	      },
221	      [consumers, setDropdownOpen]
222	    );
223	
224	    const monitoringURL = `/monitoring/query-browser?${monitoringParams.toString()}`;
225	
226	    let body: React.ReactNode;
227	    if (metricsError || consumersLoadError) {
228	      body = <div className="text-secondary">{t('Not available')}</div>;
229	    } else if (!consumerLoaded || metricsLoading || top5Data.length === 0) {
230	      body = (
231	        <ul className="co-utilization-card-popover__consumer-list">
232	          <li className="skeleton-consumer" />
233	          <li className="skeleton-consumer" />
234	          <li className="skeleton-consumer" />
235	          <li className="skeleton-consumer" />
236	          <li className="skeleton-consumer" />
237	        </ul>
238	      );
239	    } else {
240	      body = (
241	        <>
242	          <ul
243	            className="co-utilization-card-popover__consumer-list"
244	            aria-label={t('Top consumer by {{label}}', {
245	              label: model.label,
246	            })}
247	          >
248	            {top5Data &&
249	              top5Data.map((item) => {
250	                const title = String(item.x);
251	                return (
252	                  <ListItem key={title} value={item.y}>
253	                    <Link
254	                      className="co-utilization-card-popover__consumer-name"
255	                      to={resourcePathFromModel(
256	                        model,
257	                        title,
258	                        item.metric.namespace
259	                      )}
260	                    >
261	                      {title}
262	                    </Link>
263	                  </ListItem>
264	                );
265	              })}
266	          </ul>
267	          <Link to={monitoringURL}>{t('View more')}</Link>
268	        </>
269	      );
270	    }
271	
272	    const dropdownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
273	      <MenuToggle
274	        ref={toggleRef}
275	        onClick={() => setDropdownOpen((o) => !o)}
276	        isExpanded={dropdownOpen}
277	        icon={<CaretDownIcon />}
278	        aria-label={t('Select consumer type')}
279	      >
280	        {t('By {{label}}', {
281	          label: currentConsumer.model.labelKey
282	            ? currentConsumer.model.labelKey
283	            : currentConsumer.model.label,
284	        })}
285	      </MenuToggle>
286	    );
287	
288	    return (
289	      <div className="co-utilization-card-popover__body">
290	        {description && (
291	          <div className="co-utilization-card-popover__description">
292	            {description}
293	          </div>
294	        )}
295	        {children}
296	        <div className="co-utilization-card-popover__title">
297	          {consumers.length === 1
298	            ? t('Top {{label}} consumers', {
299	                label: currentConsumer.model.label.toLowerCase(),
300	              })
301	            : t('Top consumers')}
302	        </div>
303	        {consumers.length > 1 && (
304	          <Dropdown
305	            isOpen={dropdownOpen}
306	            className="co-utilization-card-popover__dropdown"
307	            onSelect={onDropdownChange}
308	            onOpenChange={(open: boolean) => setDropdownOpen(open)}
309	            toggle={dropdownToggle}
310	          >
311	            <DropdownList>{dropdownItems}</DropdownList>
312	          </Dropdown>
313	        )}
314	        {body}
315	      </div>
316	    );
317	  }
318	);
319	
320	ConsumerPopover.displayName = 'ConsumerPopover';
321	PopoverBody.displayName = 'PopoverBody';
322	
323	export default ConsumerPopover;

